// Sender Pre-Classifier — matches from address against known domain rules
const from = ($input.first().json.from || '').toLowerCase();

// Domain classification rules (first-match wins)
const rules = [
  {
    domains: ['linkedin.com','twitter.com','x.com','facebook.com','instagram.com',
              'reddit.com','github.com','discord.com','meetup.com','slack.com'],
    category: 'social'
  },
  {
    domains: ['indeed.com','glassdoor.com','levels.fyi','ziprecruiter.com','dice.com',
              'hired.com','greenhouse.io','lever.co','workday.com','myworkdayjobs.com',
              'wellfound.com','otta.com'],
    category: 'career'
  },
  {
    domains: ['amazon.com','apple.com','paypal.com','stripe.com','shopify.com',
              'ebay.com','bestbuy.com','ups.com','fedex.com','usps.com'],
    category: 'fyi'
  },
  {
    domains: ['substack.com','beehiiv.com','convertkit.com','mailchimp.com',
              'klaviyo.com','sendgrid.net','constantcontact.com'],
    category: 'newsletter'
  },
];

// Match sender domain
for (const rule of rules) {
  if (rule.domains.some(d => from.includes(d))) {
    return [{
      json: {
        ...$input.first().json,
        fast_category: rule.category,
        skip_ai: true
      }
    }];
  }
}

// No match — let AI classify
return [{
  json: {
    ...$input.first().json,
    fast_category: null,
    skip_ai: false
  }
}];

// HTML to Plain Text — strip HTML tags for the AI classifier
// DeepSeek only needs the textual content, not markup.
const html = $input.first().json.body_html || $input.first().json.body_text || $input.first().json.snippet || '';

// Simple HTML tag stripping (production-grade would use a real parser,
// but this is sufficient for the classifier's ~300 char preview)
const cleaned = html
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/\s+/g, ' ')
  .trim();

return [{
  json: {
    ...$input.first().json,
    cleaned_body: cleaned
  }
}];

// Validate + normalize DeepSeek category output
// The LLM Chain returns raw text — we extract the JSON and validate.

const validCategories = ['newsletter', 'action', 'social', 'promotions', 'career', 'fyi', 'spam'];

let rawText = '';

// Try to extract the LLM response from various N8N AI node output shapes
if ($input.first().json.text) {
  rawText = $input.first().json.text;
} else if ($input.first().json.output) {
  rawText = $input.first().json.output;
} else if ($input.first().json.response) {
  rawText = $input.first().json.response;
} else {
  // Fallback: stringify entire JSON and try regex extraction
  rawText = JSON.stringify($input.first().json);
}

// Attempt JSON parse
let category = '';
try {
  // Handle markdown code fences sometimes added by models
  const clean = rawText
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .trim();
  const parsed = JSON.parse(clean);
  category = (parsed.category || '').toString().trim().toLowerCase();
} catch {
  // Regex fallback for malformed output
  const match = rawText.match(/"category"\s*:\s*"([^"]+)"/i);
  if (match && match[1]) {
    category = match[1].trim().toLowerCase();
  }
}

// Validate and fall back to 'fyi' if invalid
const finalCategory = validCategories.includes(category) ? category : 'fyi';

return [{
  json: {
    ...$input.first().json,
    category: finalCategory
  }
}];

// Set: Normalize — ensure all required fields exist with defaults
const input = $input.first().json;
return [{
  json: {
    ...input,
    final_category: input.fast_category || input.category || 'fyi',
    account_type: input.account_type || 'unknown',
    message_id: input.message_id || input.id || '',
    thread_id: input.thread_id || input.threadId || '',
    credential_name: input.credential_name || '',
    email_address: input.email_address || ''
  }
}];

// Webhook Response — return final classification summary (resilient)
const input = $input.first().json;
return [{
  json: {
    success: !!input.final_category || !!input.category,
    account_type: input.account_type || 'unknown',
    email_address: input.email_address || '',
    message_id: input.message_id || '',
    final_category: input.final_category || input.category || 'unknown',
    classified_at: new Date().toISOString()
  }
}];

// Set: Dynamic Label — map category to Gmail label ID
const input = $input.first().json;
const labelMap = {
  newsletter: 'Label_2',
  action: 'Label_1',
  social: 'Label_3',
  promotions: 'Label_4',
  career: 'Label_5',
  fyi: 'Label_6',
  spam: 'Label_7'
};
const category = input.final_category || 'fyi';
return [{
  json: {
    ...input,
    label_id: labelMap[category] || 'Label_6',
    should_archive: category === 'promotions'
  }
}];

